package com.example.demo.controller;import com.example.demo.dto.LoteProductoDTO;import com.example.demo.services.LoteService;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/lotes")public class LoteController{private final LoteService service;public LoteController(LoteService service){this.service=service;}@GetMapping("/vencimientos")public List<LoteProductoDTO> vencimientos(@RequestParam(defaultValue="30")int dias){return service.proximosAVencer(dias);}@GetMapping("/producto/{id}")public List<LoteProductoDTO> producto(@PathVariable Long id){return service.porProducto(id);}}
